let data = $input.item.json.output;
if (typeof data === 'string') data = JSON.parse(data);

const originalBody = $('Webhook Carrusel').first().json.body;
const carousels = data.carousels[0];
const prompts = carousels.image_prompts;

// Si la IA no genero prompts, mandamos uno vacio de escape
if (!prompts || prompts.length === 0) {
  return [{ json: { prompt: "blank image", originalCarousel: data, originalBody } }];
}

return prompts.map((prompt, idx) => {
  return {
    json: {
      prompt: prompt,
      index: idx,
      originalCarousel: data,
      originalBody: originalBody
    }
  };
});

const aggregated = $input.all();
const firstItem = aggregated[0].json;

// Recuperamos los datos originales
let finalCarousel = firstItem.originalCarousel;
const originalBody = firstItem.originalBody;

// Extraemos URLs de las imagenes (DALL-E devuelve la url en un array llamado 'data')
const generatedImages = aggregated.map(item => {
  if(item.json.data && item.json.data[0] && item.json.data[0].url) {
    return item.json.data[0].url;
  }
  return null;
});

// Inyectamos las URLs en el JSON final
if (finalCarousel.carousels && finalCarousel.carousels[0] && finalCarousel.carousels[0].canva_payload) {
  generatedImages.forEach((url, idx) => {
    if(finalCarousel.carousels[0].canva_payload.pages[idx]) {
       finalCarousel.carousels[0].canva_payload.pages[idx].generated_image_url = url;
    }
  });
}

return {
  json: {
    projectId: originalBody.projectId,
    ideaIndex: originalBody.ideaIndex,
    carouselData: finalCarousel
  }
};
